const PROCESSING_FEE = 5;

const BASE_PREMIUMS: Record<string, number> = {
  sword: 100,
  amulet: 60,
  staff: 80,
  potion: 40,
  component: 25,
};

const COMPONENT_BLOCK_SIZE = 3;
const COMPONENT_BLOCK_PREMIUM = 60;

export const quote = (customer: unknown, items: unknown[]): number => {
  const typed = items as { type: string; subtype?: string }[];
  if (
    typed.length === COMPONENT_BLOCK_SIZE &&
    typed.every((i) => i.type === "component" && i.subtype === typed[0].subtype)
  ) {
    return COMPONENT_BLOCK_PREMIUM + PROCESSING_FEE;
  }
  const basePremium = typed.reduce((sum, item) => sum + BASE_PREMIUMS[item.type], 0);
  return basePremium + PROCESSING_FEE;
};

export const claim = (policy: unknown, incident: unknown): unknown => {
  return undefined as unknown;
};

