import { describe, it, expect } from "vitest";
import { quote, claim } from "./claim-office.js";

describe("MHPCO Claim Office", () => {
  describe("quote", () => {
    it("should return processing fee only for empty item list", () => {
      const customer = { yearsWithMHPCO: 0, previousContracts: 0 };
      expect(quote(customer, [])).toBe(5);
    });
    it("should return base premium plus fee for a single sword", () => {
      const customer = { yearsWithMHPCO: 0, previousContracts: 0 };
      const items = [{ type: "sword", material: "steel", enchantment: 0, cursed: false }];
      expect(quote(customer, items)).toBe(105);
    });
    it("should return base premium plus fee for a single amulet", () => {
      const customer = { yearsWithMHPCO: 0, previousContracts: 0 };
      const items = [{ type: "amulet", material: "silver", enchantment: 0, cursed: false }];
      expect(quote(customer, items)).toBe(65);
    });
    it("should return base premium plus fee for a single staff", () => {
      const customer = { yearsWithMHPCO: 0, previousContracts: 0 };
      const items = [{ type: "staff", material: "wood", enchantment: 0, cursed: false }];
      expect(quote(customer, items)).toBe(85);
    });
    it("should return base premium plus fee for a single potion", () => {
      const customer = { yearsWithMHPCO: 0, previousContracts: 0 };
      const items = [{ type: "potion", material: "glass", enchantment: 0, cursed: false }];
      expect(quote(customer, items)).toBe(45);
    });
    it("should return base premium plus fee for a single component", () => {
      const customer = { yearsWithMHPCO: 0, previousContracts: 0 };
      const items = [{ type: "component", subtype: "rune" }];
      expect(quote(customer, items)).toBe(30);
    });
    it("should apply block pricing for exactly 3 alike components", () => {
      const customer = { yearsWithMHPCO: 0, previousContracts: 0 };
      const items = [
        { type: "component", subtype: "rune" },
        { type: "component", subtype: "rune" },
        { type: "component", subtype: "rune" },
      ];
      expect(quote(customer, items)).toBe(65);
    });
    it("should sum base premiums for multiple different items", () => {
      const customer = { yearsWithMHPCO: 0, previousContracts: 0 };
      const items = [
        { type: "sword", material: "steel", enchantment: 0, cursed: false },
        { type: "amulet", material: "silver", enchantment: 0, cursed: false },
      ];
      expect(quote(customer, items)).toBe(165);
    });
    it("should apply cursed surcharge to the cursed item only", () => {
      const customer = { yearsWithMHPCO: 0, previousContracts: 0 };
      const items = [
        { type: "sword", material: "steel", enchantment: 0, cursed: true },
        { type: "amulet", material: "silver", enchantment: 0, cursed: false },
      ];
      // cursed sword: 100 base + 50 curse surcharge = 150
      // plain amulet: 60 base
      // policy base: 210, + 5 fee = 215
      expect(quote(customer, items)).toBe(215);
    });
    it("should apply high-enchantment surcharge for enchantment >= 5", () => {
      const customer = { yearsWithMHPCO: 0, previousContracts: 0 };
      const items = [{ type: "sword", material: "steel", enchantment: 5, cursed: false }];
      // sword base: 100, high-enchantment surcharge: 30 (30% of 100)
      // total: 130 base + 5 fee = 135
      expect(quote(customer, items)).toBe(135);
    });
    it("should apply loyalty discount for customer with >= 2 years", () => {
      const customer = { yearsWithMHPCO: 2, previousContracts: 0 };
      const items = [{ type: "sword", material: "steel", enchantment: 0, cursed: false }];
      // sword base: 100, loyalty discount: -20 (20% of 100), first insurance: +10 (10% of 100)
      // policy base: 90 + 5 fee = 95
      expect(quote(customer, items)).toBe(95);
    });
    it("should apply first insurance surcharge to every item in a quote", () => {
      const customer = { yearsWithMHPCO: 0, previousContracts: 0 };
      const items = [{ type: "sword", material: "steel", enchantment: 0, cursed: false }];
      // sword base: 100, first insurance surcharge: +10 (10% of 100)
      // policy base: 110 + 5 fee = 115
      expect(quote(customer, items)).toBe(115);
    });
    it.todo("should apply follow-up contract discount on second and later quotes");
  });

  describe("claim", () => {
    it.todo("should apply deductible per damage item");
    it.todo("should fully reimburse dragon-material item damage minus deductible");
    it.todo("should reimburse at 50% for item with enchantment >= 8 minus deductible");
    it.todo("should cap total payout at twice the insurance sum");
    it.todo("should track remaining cap across successive claims on same policy");
  });
});

const PROCESSING_FEE = 5;

const BASE_PREMIUMS: Record<string, number> = {
  sword: 100,
  amulet: 60,
  staff: 80,
  potion: 40,
  component: 25,
};

const COMPONENT_BLOCK_SIZE = 3;
const COMPONENT_BLOCK_PREMIUM = 60;
const CURSED_SURCHARGE_RATE = 0.5;
const HIGH_ENCHANTMENT_THRESHOLD = 5;
const HIGH_ENCHANTMENT_SURCHARGE_RATE = 0.3;
const LOYALTY_YEARS_THRESHOLD = 2;
const LOYALTY_DISCOUNT_RATE = 0.2;

export const quote = (customer: unknown, items: unknown[]): number => {
  const typedCustomer = customer as { yearsWithMHPCO: number };
  const typed = items as { type: string; subtype?: string; cursed?: boolean; enchantment?: number }[];
  const isComponentBlock =
    typed.length === COMPONENT_BLOCK_SIZE &&
    typed.every((i) => i.type === "component" && i.subtype === typed[0].subtype);
  const basePremium = isComponentBlock
    ? COMPONENT_BLOCK_PREMIUM
    : typed.reduce((sum, item) => {
        const itemBase = BASE_PREMIUMS[item.type];
        const cursedSurcharge = item.cursed ? itemBase * CURSED_SURCHARGE_RATE : 0;
        const enchantmentSurcharge = (item.enchantment ?? 0) >= HIGH_ENCHANTMENT_THRESHOLD ? itemBase * HIGH_ENCHANTMENT_SURCHARGE_RATE : 0;
        return sum + itemBase + cursedSurcharge + enchantmentSurcharge;
      }, 0);
  const loyaltyDiscount = typedCustomer.yearsWithMHPCO >= LOYALTY_YEARS_THRESHOLD ? basePremium * LOYALTY_DISCOUNT_RATE : 0;
  return basePremium - loyaltyDiscount + PROCESSING_FEE;
};

export const claim = (policy: unknown, incident: unknown): unknown => {
  return undefined as unknown;
};

