    payout += reimbursable - DEDUCTIBLE;
  }
  const finalPayout = Math.min(Math.floor(payout), typedPolicy.remainingCap);
  const remainingCap = typedPolicy.remainingCap - finalPayout;
  return { payout: finalPayout, remainingCap };
};

